+            format!("field_{i:06}"),
+            json!({
+                "index": i,
+                "value": format!("value_{i}"),
+                "nested": {
+                    "a": i * 2,
+                    "b": format!("nested_{i}")
+                }
+            }),
+        );
+    }
+    Value::Object(obj)
