+/// Builder for customizing prompt fixtures.
+#[derive(Debug, Clone)]
+pub struct PromptBuilder {
+    name: String,
+    description: Option<String>,
+    arguments: Vec<PromptArgument>,
+    version: Option<String>,
+    tags: Vec<String>,
+}
+
+impl PromptBuilder {
+    /// Creates a new prompt builder.
+    #[must_use]
+    pub fn new(name: impl Into<String>) -> Self {
+        Self {
+            name: name.into(),
+            description: None,
+            arguments: Vec::new(),
+            version: None,
+            tags: Vec::new(),
+        }
+    }
+
+    /// Sets the description.
+    #[must_use]
+    pub fn description(mut self, desc: impl Into<String>) -> Self {
+        self.description = Some(desc.into());
+        self
+    }
+
+    /// Adds a required argument.
+    #[must_use]
+    pub fn required_arg(mut self, name: impl Into<String>, desc: impl Into<String>) -> Self {
+        self.arguments.push(PromptArgument {
+            name: name.into(),
+            description: Some(desc.into()),
+            required: true,
+        });
+        self
+    }
+
+    /// Adds an optional argument.
+    #[must_use]
+    pub fn optional_arg(mut self, name: impl Into<String>, desc: impl Into<String>) -> Self {
+        self.arguments.push(PromptArgument {
+            name: name.into(),
+            description: Some(desc.into()),
+            required: false,
+        });
+        self
+    }
+
+    /// Sets the version.
+    #[must_use]
+    pub fn version(mut self, version: impl Into<String>) -> Self {
+        self.version = Some(version.into());
+        self
+    }
+
+    /// Sets tags.
+    #[must_use]
+    pub fn tags(mut self, tags: Vec<String>) -> Self {
+        self.tags = tags;
+        self
+    }
+
+    /// Builds the prompt.
+    #[must_use]
+    pub fn build(self) -> Prompt {
+        Prompt {
+            name: self.name,
+            description: self.description,
+            arguments: self.arguments,
+            icon: None,
+            version: self.version,
+            tags: self.tags,
+        }
+    }
+}
