+/// Builder for customizing tool fixtures.
+///
+/// # Example
+///
+/// ```ignore
+/// use fastmcp::testing::fixtures::tools::ToolBuilder;
+///
+/// let tool = ToolBuilder::new("custom_tool")
+///     .description("A custom tool for testing")
+///     .with_string_param("input", "The input string", true)
+///     .with_number_param("count", "Number of times", false)
+///     .build();
+/// ```
+#[derive(Debug, Clone)]
+pub struct ToolBuilder {
+    name: String,
+    description: Option<String>,
+    properties: serde_json::Map<String, serde_json::Value>,
+    required: Vec<String>,
+    output_schema: Option<serde_json::Value>,
+    version: Option<String>,
+    tags: Vec<String>,
+    annotations: Option<ToolAnnotations>,
+}
+
+impl ToolBuilder {
+    /// Creates a new tool builder with the given name.
+    #[must_use]
+    pub fn new(name: impl Into<String>) -> Self {
+        Self {
+            name: name.into(),
+            description: None,
+            properties: serde_json::Map::new(),
+            required: Vec::new(),
+            output_schema: None,
+            version: None,
+            tags: Vec::new(),
+            annotations: None,
+        }
+    }
+
+    /// Sets the tool description.
+    #[must_use]
+    pub fn description(mut self, desc: impl Into<String>) -> Self {
+        self.description = Some(desc.into());
+        self
+    }
+
+    /// Adds a string parameter.
+    #[must_use]
+    pub fn with_string_param(mut self, name: impl Into<String>, desc: impl Into<String>, required: bool) -> Self {
+        let name = name.into();
+        self.properties.insert(
+            name.clone(),
+            json!({
+                "type": "string",
+                "description": desc.into()
+            }),
+        );
+        if required {
+            self.required.push(name);
+        }
+        self
+    }
+
+    /// Adds a number parameter.
+    #[must_use]
+    pub fn with_number_param(mut self, name: impl Into<String>, desc: impl Into<String>, required: bool) -> Self {
+        let name = name.into();
+        self.properties.insert(
+            name.clone(),
+            json!({
+                "type": "number",
+                "description": desc.into()
+            }),
+        );
+        if required {
+            self.required.push(name);
+        }
+        self
+    }
+
+    /// Adds a boolean parameter.
+    #[must_use]
+    pub fn with_bool_param(mut self, name: impl Into<String>, desc: impl Into<String>, required: bool) -> Self {
+        let name = name.into();
+        self.properties.insert(
+            name.clone(),
+            json!({
+                "type": "boolean",
+                "description": desc.into()
+            }),
+        );
+        if required {
+            self.required.push(name);
+        }
+        self
+    }
+
+    /// Sets the output schema.
+    #[must_use]
+    pub fn output_schema(mut self, schema: serde_json::Value) -> Self {
+        self.output_schema = Some(schema);
+        self
+    }
+
+    /// Sets the version.
+    #[must_use]
+    pub fn version(mut self, version: impl Into<String>) -> Self {
+        self.version = Some(version.into());
+        self
+    }
+
+    /// Adds tags.
+    #[must_use]
+    pub fn tags(mut self, tags: Vec<String>) -> Self {
+        self.tags = tags;
+        self
+    }
+
+    /// Sets the annotations.
+    #[must_use]
+    pub fn annotations(mut self, annotations: ToolAnnotations) -> Self {
+        self.annotations = Some(annotations);
+        self
+    }
+
+    /// Builds the tool.
+    #[must_use]
+    pub fn build(self) -> Tool {
+        let input_schema = json!({
+            "type": "object",
+            "properties": self.properties,
+            "required": self.required
+        });
+
+        Tool {
+            name: self.name,
+            description: self.description,
+            input_schema,
+            output_schema: self.output_schema,
+            icon: None,
+            version: self.version,
+            tags: self.tags,
+            annotations: self.annotations,
+        }
+    }
+}
